fix_template:
# Wrap event handler body in try/catch
# For button handlers:
$btn.Add_Click({
    try {
        # <original handler body>
    } catch {
        Write-AppLog "Handler error: $_" -Level Error
    }
})

# For timer Tick handlers (stop timer on error to prevent repeat crashes):
$timer.Add_Tick({
    try {
        # <original handler body>
    } catch {
        $this.Stop()
        Write-AppLog "Timer error: $_" -Level Error
    }
})
